using System.Numerics;
using UnityEngine;

[RequireComponent(typeof(MeshFilter), typeof(MeshRenderer))]
public class Chunk : MonoBehaviour
{
    MeshFilter meshFilter;

    void Awake()
    {
        meshFilter = GetComponent<MeshFilter>();
    }

    public void ApplyMesh(UnityEngine.Vector3[] vertices, int[] triangles, Texture2D texture)
    {
        Mesh mesh = new Mesh();
        mesh.indexFormat = (vertices.Length > 65000) ? UnityEngine.Rendering.IndexFormat.UInt32 : UnityEngine.Rendering.IndexFormat.UInt16;

        int resolution = Mathf.FloorToInt(Mathf.Sqrt(vertices.Length));
        UnityEngine.Vector2[] uv = new UnityEngine.Vector2[vertices.Length];
        if (resolution <= 1)
        {
            for (int i = 0; i < uv.Length; i++) uv[i] = UnityEngine.Vector2.zero;
        }
        else
        {
            for (int y = 0; y < resolution; y++)
            {
                for (int x = 0; x < resolution; x++)
                {
                    uv[x + y * resolution] = new UnityEngine.Vector2((float)x / (resolution - 1), (float)y / (resolution - 1));
                }
            }
        }

        GetComponent<Renderer>().material.SetTexture("_BaseMap", texture);
        GetComponent<Renderer>().material.SetTexture("_MainTex", texture);

        mesh.vertices = vertices;
        mesh.uv = uv;
        mesh.triangles = triangles;
        mesh.RecalculateNormals();
        mesh.RecalculateBounds();

        meshFilter.mesh = mesh;
    }
}

